THOUGHT: The current heuristic for marking the switch default as unreachable is unsound. A safer approach is to verify per predecessor edge whether LazyValueInfo proves the condition is a constant that matches one of the explicit case values. Only if every incoming edge is covered should we mark the default unreachable. I will replace the existing CR.isSingleElement() check with this per-edge coverage check.

```bash
sed -i '413,431{s/.*/    if (ReachableCaseCount > 1 && !SI->defaultDestUnreachable()) {
      BasicBlock *DefaultDest = SI->getDefaultDest();
      // The default dest is unreachable only if, for every incoming edge, LVI
      // proves the condition is a constant that matches one of the explicit cases.
      bool AllCovered = true;
      for (auto *Pred : predecessors(BB)) {
        Constant *EdgeConst = LVI->getConstantOnEdge(Cond, Pred, BB, I);
        if (!EdgeConst) { AllCovered = false; break; }
        bool MatchesSomeCase = false;
        for (auto CI2 = SI->case_begin(), CE2 = SI->case_end(); CI2 != CE2; ++CI2) {
          if (CI2->getCaseValue() == EdgeConst) { MatchesSomeCase = true; break; }
        }
        if (!MatchesSomeCase) { AllCovered = false; break; }
      }
      if (AllCovered) {
        BasicBlock *NewUnreachableBB =
            BasicBlock::Create(BB->getContext(), "default.unreachable",
                               BB->getParent(), DefaultDest);
        new UnreachableInst(BB->getContext(), NewUnreachableBB);

        DefaultDest->removePredecessor(BB);
        SI->setDefaultDest(NewUnreachableBB);

        if (SuccessorsCount[DefaultDest] == 1)
          DTU.applyUpdates({{DominatorTree::Delete, BB, DefaultDest}});
        DTU.applyUpdates({{DominatorTree::Insert, BB, NewUnreachableBB}});

        ++NumDeadCases;
        Changed = true;
      }
    }/}' llvm/lib/Transforms/Scalar/CorrelatedValuePropagation.cpp && submit-patch
```

